{"document": {"category": "csaf_security_advisory", "csaf_version": "2.0", "distribution": {"text": "Disclosure is not limited. (TLPv2: TLP:CLEAR)", "tlp": {"label": "WHITE"}}, "lang": "en", "notes": [{"category": "summary", "text": "Simcenter Femap is affected by file parsing vulnerabilities in Datakit library and Parasolid Translator Component that could be triggered when the application reads files in IPT or IGS format. If a user is tricked to open a malicious file with the affected application, an attacker could leverage the vulnerability to perform remote code execution in the context of the current process.

Siemens has released a new version for Simcenter Femap and recommends to update to the latest version.", "title": "Summary"}, {"category": "general", "text": "As a general security measure, Siemens strongly recommends to protect network access to devices with appropriate mechanisms. In order to operate the devices in a protected IT environment, Siemens recommends to configure the environment according to Siemens' operational guidelines for Industrial Security (Download: https://www.siemens.com/cert/operational-guidelines-industrial-security), and to follow the recommendations in the product manuals.
Additional information on Industrial Security by Siemens can be found at: https://www.siemens.com/industrialsecurity", "title": "General Recommendations"}, {"category": "general", "text": "For further inquiries on security vulnerabilities in Siemens products and solutions, please contact the Siemens ProductCERT: https://www.siemens.com/cert/advisories", "title": "Additional Resources"}, {"category": "legal_disclaimer", "text": "The use of Siemens Security Advisories is subject to the terms and conditions listed on: https://www.siemens.com/productcert/terms-of-use.", "title": "Terms of Use"}], "publisher": {"category": "vendor", "contact_details": "productcert@siemens.com", "name": "Siemens ProductCERT", "namespace": "https://www.siemens.com"}, "references": [{"category": "self", "summary": "SSA-870926: Datakit and Parasolid Vulnerabilities in Simcenter Femap - HTML Version", "url": "https://cert-portal.siemens.com/productcert/html/ssa-870926.html"}, {"category": "self", "summary": "SSA-870926: Datakit and Parasolid Vulnerabilities in Simcenter Femap - CSAF Version", "url": "https://cert-portal.siemens.com/productcert/csaf/ssa-870926.json"}], "title": "SSA-870926: Datakit and Parasolid Vulnerabilities in Simcenter Femap", "tracking": {"current_release_date": "2026-06-09T00:00:00.000Z", "generator": {"engine": {"name": "Siemens ProductCERT CSAF Generator", "version": "1"}}, "id": "SSA-870926", "initial_release_date": "2026-05-12T00:00:00.000Z", "revision_history": [{"date": "2026-05-12T00:00:00.000Z", "legacy_version": "1.0", "number": "1", "summary": "Publication Date"}, {"date": "2026-06-09T00:00:00.000Z", "legacy_version": "1.1", "number": "2", "summary": "Added CVE-2025-40936"}], "status": "interim", "version": "2"}}, "product_tree": {"branches": [{"branches": [{"branches": [{"category": "product_version_range", "name": "vers:intdot/<2512.0003", "product": {"name": "Simcenter Femap", "product_id": "1"}}], "category": "product_name", "name": "Simcenter Femap"}], "category": "vendor", "name": "Siemens"}]}, "vulnerabilities": [{"cve": "CVE-2025-12659", "cwe": {"id": "CWE-122", "name": "Heap-based Buffer Overflow"}, "notes": [{"category": "summary", "text": "The affected applications contains a memory corruption vulnerability while parsing specially crafted IPT files. This could allow an attacker to execute code in the context of the current process. (ZDI-CAN-27349, ZDI-CAN-27389)", "title": "Summary"}], "product_status": {"known_affected": ["1"]}, "remediations": [{"category": "vendor_fix", "details": "Update to V2512.0003 or later version", "product_ids": ["1"], "url": "https://support.sw.siemens.com/product/275652363/"}], "scores": [{"cvss_v3": {"baseScore": 7.8, "baseSeverity": "HIGH", "vectorString": "CVSS:3.1/AV:L/AC:L/PR:N/UI:R/S:U/C:H/I:H/A:H", "version": "3.1"}, "products": ["1"]}], "title": "CVE-2025-12659"}, {"cve": "CVE-2025-40936", "cwe": {"id": "CWE-125", "name": "Out-of-bounds Read"}, "notes": [{"category": "summary", "text": "The affected applications contains an out of bounds read vulnerability while parsing specially crafted IGS files. This could allow an attacker to crash the application or execute code in the context of the current process. (ZDI-CAN-26755)", "title": "Summary"}], "product_status": {"known_affected": ["1"]}, "remediations": [{"category": "vendor_fix", "details": "Update to V2512.0003 or later version", "product_ids": ["1"], "url": "https://support.sw.siemens.com/product/275652363/"}], "scores": [{"cvss_v3": {"baseScore": 7.8, "baseSeverity": "HIGH", "vectorString": "CVSS:3.1/AV:L/AC:L/PR:N/UI:R/S:U/C:H/I:H/A:H", "version": "3.1"}, "products": ["1"]}], "title": "CVE-2025-40936"}]}
